public int findChair(int[][] times, int targetFriend) {
    int n = times.length;
    List<int[]> events = new ArrayList<>();
    for (int i = 0; i < n; i++) {
        events.add(new int[]{times[i][0], i});
        events.add(new int[]{times[i][1], ~i});
    }
    events.sort((a, b) -> Integer.compare(a[0], b[0]));
    int[] chairs = new int[n];
    TreeSet<Integer> availableChairs = new TreeSet<>();
    for (int i = 0; i < n; i++) {
        availableChairs.add(i);
    }
    for (int[] event : events) {
        if (event[1] >= 0) {
            int friendId = event[1];
            chairs[friendId] = availableChairs.first();
            availableChairs.remove(availableChairs.first());
            if (friendId == targetFriend) {
                return chairs[friendId];
            }
        } else {
            int friendId = ~event[1];
            availableChairs.add(chairs[friendId]);
        }
    }
    return -1;
}
```


